$_LANG['cloudx_hosting_servers_section_7_description_1'] = "¿Qué es un certificado SSL?";
$_LANG['cloudx_hosting_servers_section_7_description_2'] = "AEl certificado N SSL es un certificado digital que autentica la identidad de un sitio web y habilita una conexión encriptada.SSL representa la capa de enchufes seguros, un protocolo de seguridad que crea un enlace cifrado entre un servidor web y un navegador web.";
$_LANG['cloudx_hosting_servers_section_7_description_3'] = "¿Cuál es el beneficio de SSL?";
