$_LANG['cloudx_hosting_servers_section_7_description_5'] = "¿SSL funciona en todos los navegadores web?";
$_LANG['cloudx_hosting_servers_section_7_description_6'] = "Un certificado SSL es un certificado digital que autentica la identidad de un sitio web y habilita una conexión cifrada.SSL representa la capa de enchufes seguros, un protocolo de seguridad que crea un enlace cifrado entre un servidor web y un navegador web.";
$_LANG['cloudx_hosting_servers_section_7_description_7'] = "¿Cómo solicito un SSL?";
$_LANG['cloudx_hosting_servers_section_7_description_8'] = "Un certificado SSL es un certificado digital que autentica la identidad de un sitio web y habilita una conexión cifrada.SSL significa Secure Sockets Layer, un protocolo de seguridad que crea un enlace encriptado entre un servidor web y un navegador web.";
$_LANG['cloudx_hosting_servers_section_7_description_9'] = "¿Cómo genero una solicitud de firma de certificado (CSR)?";
